def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an athlete (or related entities) into a single fluent sentence.
    """
    if not triples:
        return ""

    # Build entity relationships to create connected sentences
    entity_info = {}
    for triple in triples:
        subj = triple.subject
        pred = triple.predicate.lower()
        obj = triple.object

        if subj not in entity_info:
            entity_info[subj] = []
        entity_info[subj].append((pred, obj))

        # Find main subject (athlete or most central entity)
        main_subject = max(entity_info.keys(), key=lambda s: len(entity_info[s]))

        # Build a graph of entity relationships to connect related triples
        entity_to_triples = {}
        for triple in triples:
            if triple.subject not in entity_to_triples:
                entity_to_triples[triple.subject] = []
            entity_to_triples[triple.subject].append((triple.predicate.lower(), triple.object))

        # Find connected entities (where one triple's object is another triple's subject)
        all_objects = {triple.object for triple in triples}
        connected_entities = set(entity_to_triples.keys()) & all_objects

        # Build clauses for main subject
        main_clauses = []
        for pred, obj in entity_info.get(main_subject, []):
            clause = get_predicate_clause(pred, obj, main_subject)
            if clause:
                main_clauses.append(clause)

        # Build clauses for connected entities (nested information)
        connected_clauses = []
        for entity in connected_entities:
            if entity != main_subject and entity in entity_to_triples:
                for pred, obj in entity_to_triples[entity]:
                    clause = get_predicate_clause(pred, obj, entity)
                    if clause:
                        connected_clauses.append((entity, clause))

        # Construct complex sentence connecting all information
        if main_clauses and connected_clauses:
            # Connect main subject with its connected entities
            main_text = main_clauses[0]
            for i, clause in enumerate(main_clauses[1:]):
                main_text += f", {clause}"

            # Add connected entity information with relative clauses
            for entity, clause in connected_clauses:
                if "manager" in str(connected_clauses[0]) or "coach" in str(connected_clauses[0]):
                    main_text += f", which is {clause}"
                else:
                    main_text += f", where {clause}"

            sentence = f"{main_subject} {main_text}."
        elif main_clauses:
            if len(main_clauses) == 1:
                sentence = f"{main_subject} {main_clauses[0]}."
            else:
                main_text = main_clauses[0]
                for clause in main_clauses[1:]:
                    main_text += f", {clause}"
                sentence = f"{main_subject} {main_text}."
        else:
            sentence = f"{main_subject}."

        # Capitalize first character
        return sentence[0].upper() + sentence[1:]

